package com.xoxo.pos.security;
import com.xoxo.pos.users.Role;import io.jsonwebtoken.*;import io.jsonwebtoken.security.Keys;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import javax.crypto.SecretKey;import java.nio.charset.StandardCharsets;import java.util.Date;
@Service public class JwtService{@Value("${app.jwt.secret}") private String secret;@Value("${app.jwt.expiration-minutes}") private long expirationMinutes;private SecretKey key(){return Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));}public String generate(String u,Role r){var now=new Date();var exp=new Date(now.getTime()+expirationMinutes*60000);return Jwts.builder().subject(u).claim("role",r.name()).issuedAt(now).expiration(exp).signWith(key()).compact();}public Claims parse(String t){return Jwts.parser().verifyWith(key()).build().parseSignedClaims(t).getPayload();}}
